function ticker(e){var t={USD:"$",CNY:"\xa5",JPY:"\xa5",EUR:"\u20ac"};$.ajax({type:"GET",url:"https://api.coingecko.com/api/v3/simple/price?ids=bitcoin-cash&vs_currencies="+e.toLowerCase(),contentType:"application/json; charset=utf-8",timeout:6e3,error:function(){$("#ticker_value").html().includes("BCH")||$("#ticker_value").html("N/A")},success:function(e){var i=[],c=e["bitcoin-cash"]||{};$.each(c,function(e,c){var r=t[e.toUpperCase()];void 0!==r&&i.push("BCH/"+e.toUpperCase()+"&nbsp;"+r+c)}),i.length>0?$("#ticker_value").html(i.join(" &bull; ")):$("#ticker_value").html().includes("BCH")||$("#ticker_value").html("N/A")}}).done(function(){setTimeout(function(){ticker(ticker_currencies)},update_interval)}).fail(function(){setTimeout(function(){ticker(ticker_currencies)},update_interval)})}var ticker_currencies="USD,EUR,JPY,CNY",update_interval=3e4;ticker(ticker_currencies);